const raw = $input.first().json;
const data = raw.body ?? raw;

const appUrl = 'https://itsnomatata.com';
const appName = 'Nomatata';

const actionUrl = data.actionUrl
  ? (data.actionUrl.startsWith('http')
      ? data.actionUrl
      : `${appUrl}${data.actionUrl}`)
  : appUrl;

const fullName = data.fullName ?? data.full_name ?? 'Team Member';
const firstName = fullName.split(' ')[0];

// Extract metadata if present
const metadata = data.metadata ?? {};

// Add timestamp to metadata
metadata.sentAt = new Date().toISOString();
metadata.notificationId = data.referenceId ?? data.entityId ?? 'unknown';

return [{
  json: {
    to: data.to ?? '',
    fullName,
    firstName,
    title: data.title ?? 'You have a new notification',
    message: data.message ?? '',
    type: data.type ?? 'general',
    priority: data.priority ?? 'medium',
    actionUrl,
    metadata,
    appName,
    appUrl,
    originalPayload: data
  }
}];

const data = $input.first().json;

// Use the email template service logic
const type = data.type;
const context = {
  fullName: data.fullName,
  firstName: data.firstName,
  title: data.title,
  message: data.message,
  actionUrl: data.actionUrl,
  metadata: data.metadata,
  appName: data.appName,
  appUrl: data.appUrl
};

// Generate email HTML based on type
let emailHtml = '';
let subject = `${data.title} — ${data.appName}`;

const templates = {
  leave_request_submitted: () => {
    subject = `Leave Request Submitted — ${data.appName}`;
    return `<h2>Leave Request Submitted</h2><p>Hi ${data.firstName},</p><p>${data.message}</p><a href="${data.actionUrl}" class="button">Review Request</a>`;
  },
  leave_request_approved: () => {
    subject = `Leave Request Approved — ${data.appName}`;
    return `<h2>Leave Request Approved ✅</h2><p>Hi ${data.firstName},</p><p>${data.message}</p><a href="${data.actionUrl}" class="button">View Details</a>`;
  },
  leave_request_rejected: () => {
    subject = `Leave Request Rejected — ${data.appName}`;
    return `<h2>Leave Request Rejected ❌</h2><p>Hi ${data.firstName},</p><p>${data.message}</p><a href="${data.actionUrl}" class="button">View Details</a>`;
  },
  meeting_invitation: () => {
    subject = `Meeting Invitation — ${data.appName}`;
    return `<h2>Meeting Invitation 📅</h2><p>Hi ${data.firstName},</p><p>${data.message}</p><a href="${data.actionUrl}" class="button">Accept Invitation</a>`;
  },
  meeting_reminder: () => {
    subject = `Meeting Reminder — ${data.appName}`;
    return `<h2>Meeting Reminder ⏰</h2><p>Hi ${data.firstName},</p><p>${data.message}</p><a href="${data.actionUrl}" class="button">Join Meeting</a>`;
  },
  approval_required: () => {
    subject = `Approval Required — ${data.appName}`;
    return `<h2>Approval Required 📋</h2><p>Hi ${data.firstName},</p><p>${data.message}</p><a href="${data.actionUrl}" class="button">Review & Approve</a>`;
  },
  approval_approved: () => {
    subject = `Request Approved — ${data.appName}`;
    return `<h2>Request Approved ✅</h2><p>Hi ${data.firstName},</p><p>${data.message}</p><a href="${data.actionUrl}" class="button">View Details</a>`;
  },
  approval_rejected: () => {
    subject = `Request Rejected — ${data.appName}`;
    return `<h2>Request Rejected ❌</h2><p>Hi ${data.firstName},</p><p>${data.message}</p><a href="${data.actionUrl}" class="button">View Details</a>`;
  },
  social_media_post_published: () => {
    subject = `Social Media Post Published — ${data.appName}`;
    return `<h2>Social Media Post Published 📱</h2><p>Hi ${data.firstName},</p><p>${data.message}</p><a href="${data.actionUrl}" class="button">View Post</a>`;
  },
  social_media_post_failed: () => {
    subject = `Social Media Post Failed — ${data.appName}`;
    return `<h2>Social Media Post Failed ⚠️</h2><p>Hi ${data.firstName},</p><p>${data.message}</p><a href="${data.actionUrl}" class="button">View Details</a>`;
  },
  task_assigned: () => {
    subject = `New Task Assigned — ${data.appName}`;
    return `<h2>New Task Assigned 📝</h2><p>Hi ${data.firstName},</p><p>${data.message}</p><a href="${data.actionUrl}" class="button">View Task</a>`;
  },
  task_due_soon: () => {
    subject = `Task Due Soon — ${data.appName}`;
    return `<h2>Task Due Soon ⏰</h2><p>Hi ${data.firstName},</p><p>${data.message}</p><a href="${data.actionUrl}" class="button">View Task</a>`;
  },
  task_overdue: () => {
    subject = `Task Overdue — ${data.appName}`;
    return `<h2>Task Overdue 🚨</h2><p>Hi ${data.firstName},</p><p>${data.message}</p><a href="${data.actionUrl}" class="button">View Task</a>`;
  },
  welcome: () => {
    subject = `Welcome to ${data.appName}!`;
    return `<h2>Welcome to ${data.appName}! 🎉</h2><p>Hi ${data.firstName},</p><p>${data.message}</p><a href="${data.actionUrl}" class="button">Get Started</a>`;
  },
  password_reset: () => {
    subject = `Password Reset — ${data.appName}`;
    return `<h2>Password Reset Request 🔐</h2><p>Hi ${data.firstName},</p><p>${data.message}</p><a href="${data.actionUrl}" class="button">Reset Password</a><p style="font-size: 12px; color: #737373;">If you didn't request this, please ignore this email.</p>`;
  }
};

const templateFn = templates[type] || (() => `<h2>${data.title}</h2><p>Hi ${data.firstName},</p><p>${data.message}</p><a href="${data.actionUrl}" class="button">View Details</a>`);

const content = templateFn();

// Build full HTML email
emailHtml = `
<!DOCTYPE html>
<html>
<head>
  <meta charset="utf-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>${data.appName}</title>
  <style>
    body { font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, Oxygen, Ubuntu, Cantarell, sans-serif; background-color: #0a0a0a; margin: 0; padding: 20px; }
    .container { max-width: 600px; margin: 0 auto; background: #0a0a0a; border-radius: 16px; overflow: hidden; }
    .header { background: linear-gradient(135deg, #f97316 0%, #ea580c 100%); padding: 32px; text-align: center; }
    .header h1 { color: white; margin: 0; font-size: 24px; font-weight: 700; }
    .content { padding: 32px; color: #ffffff; }
    .content h2 { color: #ffffff; margin: 0 0 16px; font-size: 20px; font-weight: 600; }
    .content p { color: #a3a3a3; line-height: 1.6; margin: 0 0 16px; }
    .button { display: inline-block; background: #f97316; color: white; padding: 14px 32px; border-radius: 8px; text-decoration: none; font-weight: 600; margin: 16px 0; }
    .button:hover { background: #ea580c; }
    .footer { padding: 24px; text-align: center; color: #525252; font-size: 12px; border-top: 1px solid #262626; }
    .footer a { color: #f97316; text-decoration: none; }
    .metadata { background: #171717; padding: 16px; border-radius: 8px; margin: 16px 0; font-size: 13px; color: #737373; }
    .priority-high { border-left: 4px solid #ef4444; }
    .priority-medium { border-left: 4px solid #f97316; }
    .priority-low { border-left: 4px solid #22c55e; }
  </style>
</head>
<body>
  <div class="container priority-${data.priority}">
    <div class="header">
      <h1>${data.appName}</h1>
    </div>
    <div class="content">
      ${content}
    </div>
    <div class="footer">
      <p>&copy; ${new Date().getFullYear()} ${data.appName}. All rights reserved.</p>
      <p><a href="${data.appUrl}">Visit ${data.appName}</a></p>
    </div>
  </div>
</body>
</html>
`;

return [{
  json: {
    to: data.to,
    fullName: data.fullName,
    firstName: data.firstName,
    subject,
    type: data.type,
    priority: data.priority,
    actionUrl: data.actionUrl,
    emailHtml,
    metadata: data.metadata
  }
}];

const data = $input.first().json;
console.log('EMAIL SENT:', JSON.stringify({ to: data.to, type: data.type, subject: data.subject }));

// Log to external monitoring service (optional)
// await fetch('https://your-monitoring-service.com/log', {
//   method: 'POST',
//   headers: { 'Content-Type': 'application/json' },
//   body: JSON.stringify({
//     event: 'email_sent',
//     to: data.to,
//     type: data.type,
//     timestamp: new Date().toISOString()
//   })
// });

return [{ json: { ...data, logged: true, loggedAt: new Date().toISOString() } }];

const data = $input.first().json;
console.log('SKIPPED EMAIL — missing to or html:', JSON.stringify({ to: data.to, hasHtml: !!data.emailHtml }));
return [{ json: { skipped: true, reason: 'missing email or html', to: data.to, type: data.type } }];

const data = $input.first().json;
console.log('INVALID PAYLOAD:', JSON.stringify(data));
return [{ json: { error: true, reason: 'invalid payload', received: data } }];

const data = $input.first().json;
console.log('EMAIL SEND ERROR:', JSON.stringify(data));

// Log error to monitoring service
// await fetch('https://your-monitoring-service.com/error', {
//   method: 'POST',
//   headers: { 'Content-Type': 'application/json' },
//   body: JSON.stringify({
//     event: 'email_send_failed',
//     error: data.error,
//     to: data.to,
//     timestamp: new Date().toISOString()
//   })
// });

return [{ json: { errorLogged: true, error: data.error } }];
